import React, { useState } from 'react';
import './App.css';

function App() {
  // State to track which card is expanded (null means none are expanded)
  const [expandedCardIndex, setExpandedCardIndex] = useState(null);
  
  // Dummy data representing your backend response
  const internships = [
    {
      title: "Python Intern",
      company: "MagikkKraft",
      match: "33.33%",
      location: "Ahmedabad, Gujarat",
      description: "Company Overview: At MagikkKraft, we are redefining how construction projects are monitored, managed, and delivered through innovative technologies such as AI, drones, and digital twins."
    },
    {
      title: "python interns",
      company: "LOGICAL Soft Tech",
      match: "33.33%",
      location: "Indore, Madhya Pradesh",
      description: "Looking for Fresher Python / Django intern candidates who want to make a career in an IT company and want to learn on a live project on location."
    },
    {
      title: "Python Internship",
      company: "LTPL",
      match: "33.33%",
      location: "Remote / Office",
      description: "Exciting opportunity for budding Python developers to work on production-level enterprise applications."
    }
  ];

  const handleCardClick = (index) => {
    // If the clicked card is already open, close it. Otherwise, open it.
    setExpandedCardIndex(expandedCardIndex === index ? null : index);
  };

  return (
    <div className="app-container">
      {/* Dark Modern Header */}
      <header className="hero-header">
        <h1>AI Internship Recommendation Engine</h1>
        <p>Smart Internship Finder using Resume</p>
      </header>

      {/* Upload Section */}
      <div className="upload-section">
        <div className="file-input-wrapper">
          <input type="file" id="resume-upload" />
        </div>
        <button className="upload-btn">Upload Resume</button>
      </div>

      {/* Dynamic Results Content */}
      <main className="content-area">
        <h3 className="skills-heading">Detected Skills: <span className="skills-text">python, java, communication</span></h3>

        {/* CSS Grid for Job Cards */}
        <div className="recommendations-grid">
          {internships.map((job, index) => {
            const isExpanded = expandedCardIndex === index;
            
            return (
              <div 
                key={index} 
                className={`job-card ${isExpanded ? 'expanded' : ''}`}
                onClick={() => handleCardClick(index)}
              >
                <h3 className="job-title">{job.title}</h3>
                <p className="company-info"><strong>Company:</strong> {job.company}</p>
                <p className="match-pct">Match: {job.match}</p>

                {/* Conditionally render details if this specific card is clicked */}
                {isExpanded && (
                  <div className="expanded-details">
                    <p className="location-info"><strong>Location:</strong> {job.location}</p>
                    <p className="job-description">{job.description}</p>
                    <button 
                      className="apply-btn" 
                      onClick={(e) => {
                        e.stopPropagation(); // Prevents card from closing when clicking button
                        alert(`Applying to ${job.company}`);
                      }}
                    >
                      Apply Now
                    </button>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </main>
    </div>
  );
}

export default App;
